zobristPiece :: Color -> PieceType -> Square -> Word64
zobristPiece c pt (Square sq) =
    let cIdx = fromEnum c
        ptIdx = fromEnum pt
        idx = cIdx * 384 + ptIdx * 64 + sq
    in zobristPieceTable `U.unsafeIndex` idx

-- | Zobrist key for side to move (Black)
zobristBlackMove :: Word64
zobristBlackMove = 0xbe8784a233863cab

