zobristCastling :: CastlingRights -> Word64
zobristCastling cr =
    let indices = [0..63]
        f i acc = if (cr `testBit` i) then acc `xor` (zobristCastlingTable `U.unsafeIndex` i) else acc
    in foldr f 0 indices

