zobristEp :: Square -> Word64
zobristEp NoSquare = 0
zobristEp (Square sq) = zobristEpTable `U.unsafeIndex` sq

computeHash :: Board -> GameState -> Word64
computeHash b gs =
    let pieceHash = foldr xor 0 [ zobristPiece c pt sq | sq <- squares, Just (Piece c pt) <- [pieceAt b sq] ]
        turnHash = if turn gs == Black then zobristBlackMove else 0
        castlingHash = zobristCastling (castlingRights gs)
        epHash = zobristEp (epSquare gs)
    in pieceHash `xor` turnHash `xor` castlingHash `xor` epHash
